import { useEffect, useState } from "react"
import BaselineChartBTC from "./chartsbtc"
import "./crypto.css"
import bookmark from "../src/assets/bookmark.png"
import bookmark2 from "../src/assets/bookmark2.png"
function Crypto() {
  let [cryptodata, changecryptodata] = useState([])
  let [sparkline, changesparkline] = useState([])
  let [firsthtml, changefirst] = useState()
  let [bookmarksrc, bookmarkrefchange] = useState(bookmark)
  let [bool, changebool] = useState(true)
 
  useEffect(() => {
    async function fetchcoins() {
      let fetched = await fetch("https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=bitcoin,ethereum,binancecoin,ripple,solana,tron,dogecoin,monero")
      let fetchedjson = await fetched.json()
      changecryptodata(fetchedjson)
    }
    fetchcoins()
    async function fetchgraph() {
      let arr = ["BTCUSDT", "ETHUSDT", "BNBUSDT", "XRPUSDT", "SOLUSDT", "TRXUSDT", "DOGEUSDT", "XMRUSDT"]
      let response = arr.map( async (item) =>
      {
        let res = await fetch(`https://api.binance.com/api/v3/klines?symbol=${item}&interval=1h&limit=30`)
        return await res.json()
      })
      let allresult = await Promise.all(response)
      let res = allresult.map((item) => {
        return item.map((subitem) => {
          return subitem.filter((subsubitem, subsubindex) => {
            if(subsubindex == 0 || subsubindex == 4) {
              return true
            }
          })
        })
       
      })
      changesparkline(res)
    }
    fetchgraph()
  }, [])
  function favourite() {
    
    bookmarkrefchange(curr => curr == bookmark ? bookmark2 : bookmark)
  }
  useEffect(() => {
      if(cryptodata != [] && sparkline.length > 0) {
        console.log(cryptodata) 
            let res1 = sparkline.map((item, index) => {
             return  <div className="coinRow">

  <div className="coinCell coinRank">
    <p className="coinMuted">#{cryptodata[index].market_cap_rank}</p>
  </div>

  <div className="coinCell coinIdentity">
    <img
      className="coinLogo"
      src={cryptodata[index].image}
      alt={cryptodata[index].name}
    />

    <div className="coinNameWrap">
      <p className="coinName">{cryptodata[index].name}</p>
      <p className="coinTicker">{cryptodata[index].symbol.toUpperCase()}</p>
    </div>
  </div>

  <div className="coinCell coinPrice">
    <p className="coinValue">£{cryptodata[index].current_price}</p>
  </div>

  <div
    className={
      "coinCell coinChange " +
      (cryptodata[index].price_change_percentage_24h >= 0 ? "isUp" : "isDown")
    }
  >
    <p className="coinValue">{cryptodata[index].price_change_percentage_24h}%</p>
  </div>

  <div className="coinCell coinChart">
    <div className="sparkWrap">
      <BaselineChartBTC sparklinedata={sparkline[index]} />
    </div>
  </div>

  <div className="coinCell coinMcap">
    <p className="coinValue">£{cryptodata[index].market_cap}</p>
  </div>
  <div className="coinCell coinVol">
    <p className="coinValue">£{cryptodata[index].total_volume}</p>
  </div>
 <div className="coinCell" id="coinBookmark">
  <img src={bookmarksrc} onClick={() => favourite()}/>
  </div>
</div>
  })
  changefirst(res1)
}
  }, [cryptodata, sparkline, bookmarksrc])
  return<>
    {firsthtml}  
  </>
}
export default Crypto
